import{c as s,Q as n,j as t,m as e}from"./chunks/framework.Bhbi9jCp.js";const b=JSON.parse('{"title":"本地存储、Keychain / Keystore 与敏感数据","description":"","frontmatter":{},"headers":[],"relativePath":"mobileCommonLearning/15-本地存储Keychain-Keystore与敏感数据.md","filePath":"mobileCommonLearning/15-本地存储Keychain-Keystore与敏感数据.md","lastUpdated":1780912084000}'),p={name:"mobileCommonLearning/15-本地存储Keychain-Keystore与敏感数据.md"};function i(l,a,d,o,c,r){return n(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="本地存储、keychain-keystore-与敏感数据" tabindex="-1">本地存储、Keychain / Keystore 与敏感数据 <a class="header-anchor" href="#本地存储、keychain-keystore-与敏感数据" aria-label="Permalink to &quot;本地存储、Keychain / Keystore 与敏感数据&quot;">​</a></h1><p>移动端一定会存数据。问题不是&quot;能不能存&quot;,而是<strong>什么数据能存、存在哪里、丢了会怎样、泄漏会怎样</strong>。</p><p>一句话:<strong>普通数据放普通存储,敏感数据放系统安全存储,真正不能泄漏的数据不要只靠客户端保存。</strong></p><hr><h2 id="一、本地存储分几类" tabindex="-1">一、本地存储分几类 <a class="header-anchor" href="#一、本地存储分几类" aria-label="Permalink to &quot;一、本地存储分几类&quot;">​</a></h2><p>移动端常见本地存储:</p><table tabindex="0"><thead><tr><th>类型</th><th>适合存什么</th><th>不适合存什么</th></tr></thead><tbody><tr><td>配置存储</td><td>主题、开关、引导页状态</td><td>token、密码、密钥</td></tr><tr><td>文件存储</td><td>图片、缓存、离线资源</td><td>明文敏感材料</td></tr><tr><td>数据库存储</td><td>会话列表、业务数据、索引</td><td>未加密隐私字段</td></tr><tr><td>安全存储</td><td>refresh token、设备密钥、登录凭据</td><td>大体积业务数据</td></tr><tr><td>系统缓存</td><td>网络缓存、图片缓存</td><td>任何必须长期可靠保存的数据</td></tr></tbody></table><p>不要把&quot;本地能读写&quot;理解成&quot;本地可靠&quot;。</p><p>客户端本地数据可能因为卸载、清缓存、系统回收、备份恢复、换机、越狱/root、调试抓取而变化。</p><hr><h2 id="二、android-和-ios-的安全存储" tabindex="-1">二、Android 和 iOS 的安全存储 <a class="header-anchor" href="#二、android-和-ios-的安全存储" aria-label="Permalink to &quot;二、Android 和 iOS 的安全存储&quot;">​</a></h2><p>Android 常见方案:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Android Keystore</span></span>
<span class="line"><span>EncryptedSharedPreferences</span></span>
<span class="line"><span>EncryptedFile</span></span>
<span class="line"><span>Room + SQLCipher</span></span></code></pre></div><p>iOS 常见方案:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Keychain</span></span>
<span class="line"><span>Secure Enclave</span></span>
<span class="line"><span>File Protection</span></span>
<span class="line"><span>加密数据库</span></span></code></pre></div><p>关键区别:</p><table tabindex="0"><thead><tr><th>平台</th><th>重点</th></tr></thead><tbody><tr><td>Android</td><td>Keystore 更像密钥容器,业务数据通常要自己加密后存</td></tr><tr><td>iOS</td><td>Keychain 适合小体积凭据,可配置访问时机和迁移属性</td></tr></tbody></table><p>安全存储不是保险箱万能钥匙。它只能降低攻击成本,不能让客户端数据绝对安全。</p><hr><h2 id="三、什么算敏感数据" tabindex="-1">三、什么算敏感数据 <a class="header-anchor" href="#三、什么算敏感数据" aria-label="Permalink to &quot;三、什么算敏感数据&quot;">​</a></h2><p>下面这些默认按敏感数据处理:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>access token</span></span>
<span class="line"><span>refresh token</span></span>
<span class="line"><span>用户手机号、邮箱、身份证、地址</span></span>
<span class="line"><span>支付凭据</span></span>
<span class="line"><span>会话 cookie</span></span>
<span class="line"><span>私有 API key</span></span>
<span class="line"><span>设备绑定密钥</span></span>
<span class="line"><span>企业内部接口地址</span></span>
<span class="line"><span>第三方平台 secret</span></span></code></pre></div><p>注意:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端里没有真正的 secret</span></span></code></pre></div><p>只要 App 发给用户,代码和资源就有被反编译、动态调试、抓包的可能。服务端 secret、私钥、管理 token 不应该放进客户端。</p><hr><h2 id="四、token-应该怎么存" tabindex="-1">四、token 应该怎么存 <a class="header-anchor" href="#四、token-应该怎么存" aria-label="Permalink to &quot;四、token 应该怎么存&quot;">​</a></h2><p>常见做法:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>access token:短期有效,内存优先,必要时安全存储</span></span>
<span class="line"><span>refresh token:安全存储,生命周期更严格</span></span>
<span class="line"><span>登录态标记:普通存储可以,但不能作为权限依据</span></span>
<span class="line"><span>用户资料缓存:按字段分级,敏感字段加密或不落盘</span></span></code></pre></div><p>不要这样做:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把 token 写进日志</span></span>
<span class="line"><span>把 token 放 URL query</span></span>
<span class="line"><span>把 token 存普通 SharedPreferences / UserDefaults</span></span>
<span class="line"><span>把 refresh token 放 WebView localStorage</span></span>
<span class="line"><span>把所有环境共用同一个 token key</span></span></code></pre></div><p>服务端仍然必须校验 token 有效性、权限、设备状态和风控状态。</p><hr><h2 id="五、keychain-和-keystore-的常见坑" tabindex="-1">五、Keychain 和 Keystore 的常见坑 <a class="header-anchor" href="#五、keychain-和-keystore-的常见坑" aria-label="Permalink to &quot;五、Keychain 和 Keystore 的常见坑&quot;">​</a></h2><p>iOS Keychain 常见坑:</p><table tabindex="0"><thead><tr><th>问题</th><th>说明</th></tr></thead><tbody><tr><td>卸载后可能仍保留</td><td>Keychain 数据不一定随 App 卸载清掉</td></tr><tr><td>访问组配置错误</td><td>App Group / Keychain Sharing 不匹配会读不到</td></tr><tr><td>备份迁移属性不清</td><td>换机后是否迁移取决于 accessibility 配置</td></tr><tr><td>生物识别变化</td><td>指纹/面容变化可能导致受保护项不可读</td></tr></tbody></table><p>Android Keystore 常见坑:</p><table tabindex="0"><thead><tr><th>问题</th><th>说明</th></tr></thead><tbody><tr><td>系统升级或设备安全状态变化</td><td>某些密钥可能失效</td></tr><tr><td>指纹变化</td><td>绑定认证的 key 可能不可用</td></tr><tr><td>厂商实现差异</td><td>旧设备或定制系统行为不完全一致</td></tr><tr><td>只存 key 不存策略</td><td>过期、轮换、重建逻辑缺失</td></tr></tbody></table><p>安全存储读失败不是小概率异常,要当作正常分支处理。</p><hr><h2 id="六、本地数据要设计生命周期" tabindex="-1">六、本地数据要设计生命周期 <a class="header-anchor" href="#六、本地数据要设计生命周期" aria-label="Permalink to &quot;六、本地数据要设计生命周期&quot;">​</a></h2><p>每类数据都要回答:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>什么时候写入?</span></span>
<span class="line"><span>什么时候读取?</span></span>
<span class="line"><span>什么时候过期?</span></span>
<span class="line"><span>什么时候清除?</span></span>
<span class="line"><span>能不能跨版本迁移?</span></span>
<span class="line"><span>能不能跨设备迁移?</span></span>
<span class="line"><span>丢了是否能重建?</span></span>
<span class="line"><span>泄漏是否需要踢登录?</span></span></code></pre></div><p>示例:</p><table tabindex="0"><thead><tr><th>数据</th><th>生命周期</th></tr></thead><tbody><tr><td>access token</td><td>短期有效,过期刷新,退出登录清除</td></tr><tr><td>refresh token</td><td>长期但可吊销,换密码或风控时失效</td></tr><tr><td>图片缓存</td><td>可删除,可重建</td></tr><tr><td>离线业务数据</td><td>需要版本号和迁移策略</td></tr><tr><td>设备密钥</td><td>丢失后重新注册设备</td></tr></tbody></table><p>不要把&quot;写入成功&quot;当成永久存在。</p><hr><h2 id="七、加密不是只调用一个库" tabindex="-1">七、加密不是只调用一个库 <a class="header-anchor" href="#七、加密不是只调用一个库" aria-label="Permalink to &quot;七、加密不是只调用一个库&quot;">​</a></h2><p>本地加密至少包含:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>密钥从哪里来</span></span>
<span class="line"><span>密钥怎么保存</span></span>
<span class="line"><span>密钥怎么轮换</span></span>
<span class="line"><span>数据怎么标记版本</span></span>
<span class="line"><span>解密失败怎么办</span></span>
<span class="line"><span>备份恢复后怎么办</span></span></code></pre></div><p>推荐模式:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>随机生成本地数据密钥</span></span>
<span class="line"><span>数据密钥由系统安全存储保护</span></span>
<span class="line"><span>业务数据用数据密钥加密后落盘</span></span>
<span class="line"><span>密文带版本号、算法标识和迁移信息</span></span></code></pre></div><p>不要自己发明加密算法。用平台能力和成熟库。</p><hr><h2 id="八、日志和埋点也是存储" tabindex="-1">八、日志和埋点也是存储 <a class="header-anchor" href="#八、日志和埋点也是存储" aria-label="Permalink to &quot;八、日志和埋点也是存储&quot;">​</a></h2><p>很多泄漏不是来自数据库,而是来自:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>console log</span></span>
<span class="line"><span>崩溃堆栈</span></span>
<span class="line"><span>网络请求日志</span></span>
<span class="line"><span>埋点参数</span></span>
<span class="line"><span>客服诊断日志</span></span>
<span class="line"><span>截图和录屏</span></span>
<span class="line"><span>剪贴板</span></span></code></pre></div><p>规则:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>日志默认脱敏</span></span>
<span class="line"><span>token 不进日志</span></span>
<span class="line"><span>手机号只保留后四位或 hash</span></span>
<span class="line"><span>身份证、银行卡不进客户端日志</span></span>
<span class="line"><span>崩溃平台上报前做字段过滤</span></span>
<span class="line"><span>调试日志 release 默认关闭</span></span></code></pre></div><p>线上日志要按生产数据处理。</p><hr><h2 id="九、什么时候会出事故" tabindex="-1">九、什么时候会出事故 <a class="header-anchor" href="#九、什么时候会出事故" aria-label="Permalink to &quot;九、什么时候会出事故&quot;">​</a></h2><p>常见事故:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>换机后 Keychain 数据迁移导致异常登录</span></span>
<span class="line"><span>用户卸载重装后仍读取旧凭据</span></span>
<span class="line"><span>release 日志上报了 token</span></span>
<span class="line"><span>refresh token 存在普通文件里被抓取</span></span>
<span class="line"><span>数据库升级失败导致本地数据全丢</span></span>
<span class="line"><span>Android Keystore key invalidated 后无法解密</span></span>
<span class="line"><span>WebView localStorage 保留了登录态</span></span>
<span class="line"><span>退出登录没有清空缓存和 cookie</span></span></code></pre></div><p>事故根因通常不是&quot;没有加密&quot;,而是没有把本地数据当成完整的生产系统设计。</p><hr><h2 id="十、检查清单" tabindex="-1">十、检查清单 <a class="header-anchor" href="#十、检查清单" aria-label="Permalink to &quot;十、检查清单&quot;">​</a></h2><ul><li>[ ] token 是否没有写入普通存储</li><li>[ ] refresh token 是否使用系统安全存储</li><li>[ ] 退出登录是否清理 token、cookie、WebView、缓存</li><li>[ ] 本地数据库是否有版本迁移和失败兜底</li><li>[ ] 敏感字段是否不会进入日志、埋点、崩溃上报</li><li>[ ] 安全存储读取失败是否有重新登录或重建流程</li><li>[ ] 加密数据是否带算法和版本信息</li><li>[ ] App 卸载、重装、换机、系统升级是否测过</li><li>[ ] release 包是否关闭调试日志</li><li>[ ] 服务端是否能吊销客户端凭据</li></ul><hr><h2 id="十一、结论" tabindex="-1">十一、结论 <a class="header-anchor" href="#十一、结论" aria-label="Permalink to &quot;十一、结论&quot;">​</a></h2><p>本地存储的核心不是 API,而是分级:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>可丢缓存 -&gt; 普通缓存</span></span>
<span class="line"><span>业务数据 -&gt; 数据库和迁移</span></span>
<span class="line"><span>敏感凭据 -&gt; Keychain / Keystore</span></span>
<span class="line"><span>服务端秘密 -&gt; 不进客户端</span></span></code></pre></div><p>客户端只负责降低泄漏概率,最终安全边界必须在服务端。</p>`,73)])])}const u=s(p,[["render",i]]);export{b as __pageData,u as default};
